select v_1 as "s_name", v_2 as "numwait" from (select v_3 as v_1, count(*) as v_2 from (select * from (select * from (select * from (select * from (select * from (select "s_suppkey" as v_4, "s_name" as v_3, "s_address" as v_5, "s_nationkey" as v_6, "s_phone" as v_7, "s_acctbal" as v_8, "s_comment" as v_9 from "supplier") l inner join (select * from (select "l_orderkey" as v_10, "l_partkey" as v_11, "l_suppkey" as v_12, "l_linenumber" as v_13, "l_quantity" as v_14, "l_extendedprice" as v_15, "l_discount" as v_16, "l_tax" as v_17, "l_returnflag" as v_18, "l_linestatus" as v_19, "l_shipdate" as v_20, "l_commitdate" as v_21, "l_receiptdate" as v_22, "l_shipinstruct" as v_23, "l_shipmode" as v_24, "l_comment" as v_25 from "lineitem") s where v_22 > v_21) r on v_4 = v_12) l inner join (select * from (select "o_orderkey" as v_26, "o_custkey" as v_27, "o_orderstatus" as v_28, "o_totalprice" as v_29, "o_orderdate" as v_30, "o_orderpriority" as v_31, "o_clerk" as v_32, "o_shippriority" as v_33, "o_comment" as v_34 from "orders") s where v_28 = 'F') r on v_26 = v_10) l inner join (select * from (select "n_nationkey" as v_35, "n_name" as v_36, "n_regionkey" as v_37, "n_comment" as v_38 from "nation") s where v_36 = 'SAUDI ARABIA') r on v_6 = v_35) l where exists(select * from (select "l_orderkey" as v_39, "l_partkey" as v_40, "l_suppkey" as v_41, "l_linenumber" as v_42, "l_quantity" as v_43, "l_extendedprice" as v_44, "l_discount" as v_45, "l_tax" as v_46, "l_returnflag" as v_47, "l_linestatus" as v_48, "l_shipdate" as v_49, "l_commitdate" as v_50, "l_receiptdate" as v_51, "l_shipinstruct" as v_52, "l_shipmode" as v_53, "l_comment" as v_54 from "lineitem") r where (v_39 = v_10) and (v_41 <> v_12))) l where not exists(select * from (select "l_orderkey" as v_55, "l_partkey" as v_56, "l_suppkey" as v_57, "l_linenumber" as v_58, "l_quantity" as v_59, "l_extendedprice" as v_60, "l_discount" as v_61, "l_tax" as v_62, "l_returnflag" as v_63, "l_linestatus" as v_64, "l_shipdate" as v_65, "l_commitdate" as v_66, "l_receiptdate" as v_67, "l_shipinstruct" as v_68, "l_shipmode" as v_69, "l_comment" as v_70 from "lineitem") r where ((v_55 = v_10) and (v_57 <> v_12)) and (v_67 > v_66))) s group by 1) s order by v_2 desc, v_1 limit 100
